// Satıcı tipi key mapping
export const SATICI_TIPI_KEY = {
  'Kategori Komisyon % (KDV Dahil)': 'KatKom',
  'Seviye 5 Satıcı Komisyon % (KDV Dahil)': 'Sv5',
  'Seviye 4 Satıcı Komisyon % (KDV Dahil)': 'Sv4',
  'Seviye 3 Satıcı Komisyon % (KDV Dahil)': 'Sv3',
  'Özelleşmiş Grup Satıcılar Komisyon % (KDV Dahil)': 'Ozl',
  'Kadın Girişimci / Kadın Kooperatifler Özel Komisyon % (KDV Dahil)': 'KadinGir',
};

export function komisyonOrani(urunGrubu, saticiTipi) {
  // Hem kısa key ('KatKom') hem tam isim ('Kategori Komisyon...') destekle
  const KISALAR = ['KatKom','Sv5','Sv4','Sv3','Ozl','KadinGir'];
  const key = KISALAR.includes(saticiTipi)
    ? saticiTipi
    : (SATICI_TIPI_KEY[saticiTipi] || 'KadinGir');
  const grup = GRUP_KOMISYON[urunGrubu];
  if (!grup) return 0.04;
  return grup[key] || 0.04;
}
